/* Look up pre-packed LexChar metadata for a codepoint.
   Returns W_TAG_LEXCHAR | metadata. Caller ORs in (cp << 18) for the final value.
   Result can be used directly with w_int() or stored as-is. */
static inline uint64_t w_lexchar_cached(uint32_t codepoint) {
    if (codepoint >= 0x110000) return 0xFFFC40000000EF80ULL;
    uint32_t block = codepoint >> 8;
    uint32_t offset = codepoint & 0xFF;
    return w_lexchar_block_data[w_lexchar_block_index[block]][offset];
}
